const items = $input.all();

function formatearFechaHora(fecha) {
  // si tiene hora
  if (fecha.dateTime) {
    return fecha.dateTime.substring(0, 16).replace("T", " ");
  }

  // si es evento de día completo
  if (fecha.date) {
    return `${fecha.date} (todo el día)`;
  }

  return "Sin fecha";
}

// Crear texto de cada evento
const eventos = items.map(item => {

  const summary = item.json.summary ?? "Sin descripción";
  const inicio = formatearFechaHora(item.json.start);
  const fin = formatearFechaHora(item.json.end);

  return `${summary}
inicio: ${inicio}
fin: ${fin}`;
});

// Mensaje final
const mensajeFinal = `Otros:
${eventos.join("\n\n")}`;

return [
  {
    json: {
      mensaje: mensajeFinal
    }
  }
];

const mensajes = items
